create or replace view sch_report_sepa.account as select s.* from account s where s.competent_authority = 'SCOTLAND';
create or replace view sch_report_sepa.account_contact as select s.* from account_contact s where exists (select null from account a where a.id = s.account_id and a.competent_authority = 'SCOTLAND');
create or replace view sch_report_sepa.account_ca_external_contacts as select s.* from account_ca_external_contacts s where s.competent_authority = 'SCOTLAND';
create or replace view sch_report_sepa.au_authority as select s.* from au_authority s where s.competent_authority = 'SCOTLAND' or s.verification_body_id is not null or exists (select null from account a where a.id = s.account_id and a.competent_authority = 'SCOTLAND');
create or replace view sch_report_sepa.au_authority_permission as select s.* from au_authority_permission s where exists (select null from au_authority aa where aa.id = s.authority_id and (aa.competent_authority = 'SCOTLAND' or aa.verification_body_id is not null or exists (select null from account a where a.id = aa.account_id and a.competent_authority = 'SCOTLAND')));
create or replace view sch_report_sepa.au_role as select s.* from au_role s;
create or replace view sch_report_sepa.au_role_permission as select s.* from au_role_permission s;
create or replace view sch_report_sepa.request_type as select rt.* from request_type rt;
create or replace view sch_report_sepa.request as SELECT r.id, r.type_id, r.status, r.creation_date, ca.resource_id AS competent_authority, acc.resource_id AS account_id, vb.resource_id AS verification_body_id, r.payload, r.submission_date, r.metadata, r.end_date FROM request r JOIN request_resource ca ON r.id = ca.request_id AND ca.resource_type = 'CA' LEFT JOIN request_resource acc ON r.id = acc.request_id AND acc.resource_type = 'ACCOUNT' LEFT JOIN request_resource vb ON r.id = acc.request_id AND acc.resource_type = 'VERIFICATION_BODY' WHERE ca.resource_id = 'SCOTLAND';
create or replace view sch_report_sepa.request_action as select s.* from request_action s where exists (select null from request r join request_resource rr on r.id = rr.request_id where r.id = s.request_id and rr.resource_id = 'SCOTLAND' and rr.resource_type = 'CA');
create or replace view sch_report_sepa.request_task_type_action_type as select * from request_task_type_action_type;
create or replace view sch_report_sepa.request_task_type as select * from request_task_type;
create or replace view sch_report_sepa.request_task_action_type as select * from request_task_action_type;
create or replace view sch_report_sepa.request_task as select id, request_id, type_id, assignee, due_date, start_date, pause_date, payload, version from request_task s where exists (select null from request r join request_resource rr on r.id = rr.request_id  where r.id = s.request_id and rr.resource_id = 'SCOTLAND' and rr.resource_type = 'CA');
create or replace view sch_report_sepa.request_task_visit as select s.* from request_task_visit s where exists (select null from request_task rt join request r on r.id = rt.request_id join request_resource rr on r.id = rr.request_id where rt.id = s.task_id and rr.resource_id = 'SCOTLAND' and rr.resource_type = 'CA');
create or replace view sch_report_sepa.verification_body as select s.* from verification_body s;
create or replace view sch_report_sepa.verification_body_emission_trading_scheme as select s.* from verification_body_emission_trading_scheme s;

