create or replace view sch_report_sepa.request_resource as (select rr.* FROM request_resource rr  WHERE rr.resource_type = 'CA' and rr.resource_id = 'SCOTLAND' UNION select acc.* FROM request_resource ca JOIN request_resource acc ON ca.request_id = acc.request_id  WHERE acc.resource_type = 'ACCOUNT' and ca.resource_type = 'CA' and ca.resource_id = 'SCOTLAND');
create or replace view sch_report_opred.request_resource as (select rr.* FROM request_resource rr  WHERE rr.resource_type = 'CA' and rr.resource_id = 'OPRED' UNION select acc.* FROM request_resource ca JOIN request_resource acc ON ca.request_id = acc.request_id  WHERE acc.resource_type = 'ACCOUNT' and ca.resource_type = 'CA' and ca.resource_id = 'OPRED');
create or replace view sch_report_nrw.request_resource as (select rr.* FROM request_resource rr  WHERE rr.resource_type = 'CA' and rr.resource_id = 'WALES' UNION select acc.* FROM request_resource ca JOIN request_resource acc ON ca.request_id = acc.request_id  WHERE acc.resource_type = 'ACCOUNT' and ca.resource_type = 'CA' and ca.resource_id = 'WALES');
create or replace view sch_report_niea.request_resource as (select rr.* FROM request_resource rr  WHERE rr.resource_type = 'CA' and rr.resource_id = 'NORTHERN_IRELAND' UNION select acc.* FROM request_resource ca JOIN request_resource acc ON ca.request_id = acc.request_id  WHERE acc.resource_type = 'ACCOUNT' and ca.resource_type = 'CA' and ca.resource_id = 'NORTHERN_IRELAND');
create or replace view sch_report_ea.request_resource as (select rr.* FROM request_resource rr  WHERE rr.resource_type = 'CA' and rr.resource_id = 'ENGLAND' UNION select acc.* FROM request_resource ca JOIN request_resource acc ON ca.request_id = acc.request_id  WHERE acc.resource_type = 'ACCOUNT' and ca.resource_type = 'CA' and ca.resource_id = 'ENGLAND');

